import React, { useState, useEffect } from "react";

// Logo component
function Logo() {
  return (
    <div className="bg-blue-400 w-screen min-h-screen flex flex-col items-center justify-center">
      <img
        src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/uwa83iuw_expires_30_days.png"
        alt="Logo VASCO"
        className="w-[300px] h-[300px] object-contain"
      />
      <h1 className="text-4xl font-bold text-white mt-6">VASCO</h1>
      <p className="text-white text-lg mt-2">
        Kết nối - Học tập - Giải trí - Sáng tạo
      </p>
      <p className="text-white text-sm mt-4">By: KBKHC</p>
    </div>
  );
}

// Login component (nhỏ gọn, ví dụ)
function LoginForm({ goToRegister }) {
  return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-blue-50">
      <h2 className="text-3xl font-bold mb-6">Đăng nhập</h2>
      <input placeholder="MSSV" className="mb-3 p-2 rounded border" />
      <input placeholder="Mk" type="password" className="mb-3 p-2 rounded border" />
      <button className="mb-3 bg-blue-200 px-4 py-2 rounded">Let’s go</button>
      <button
        onClick={goToRegister}
        className="text-blue-700 underline mt-2"
      >
        Đăng ký
      </button>
    </div>
  );
}

// Register component (dựa vào code bạn)
function RegisterForm({ goToLogin }) {
  return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-blue-50">
      <h2 className="text-3xl font-bold mb-6">Đăng ký</h2>
      <input placeholder="MSSV" className="mb-2 p-2 rounded border" />
      <input placeholder="sdt" className="mb-2 p-2 rounded border" />
      <input placeholder="Mk" type="password" className="mb-2 p-2 rounded border" />
      <input placeholder="Xác thực mk" type="password" className="mb-6 p-2 rounded border" />
      <button className="mb-3 bg-blue-200 px-4 py-2 rounded">Hoàn tất rồi nhé</button>
      <button
        onClick={goToLogin}
        className="text-blue-700 underline mt-2"
      >
        Quay về đăng nhập
      </button>
    </div>
  );
}

// App chính
export default function App() {
  const [screen, setScreen] = useState("logo"); // logo | login | register

  // Tự động chuyển logo → login sau 2s
  useEffect(() => {
    if (screen === "logo") {
      const timer = setTimeout(() => setScreen("login"), 2000);
      return () => clearTimeout(timer);
    }
  }, [screen]);

  return (
    <div>
      {screen === "logo" && <Logo />}
      {screen === "login" && <LoginForm goToRegister={() => setScreen("register")} />}
      {screen === "register" && <RegisterForm goToLogin={() => setScreen("login")} />}
    </div>
  );
}
